const Fraction = require('fraction.js');

function toFraction(frac) {

  var map = {
    '1:4': "ГӮВј",
    '1:2': "ГӮВҪ",
    '3:4': "ГӮВҫ",
    '1:7': "ГўвҖҰВҗ",
    '1:9': "ГўвҖҰвҖҳ",
    '1:10': "ГўвҖҰвҖҷ",
    '1:3': "ГўвҖҰвҖң",
    '2:3': "ГўвҖҰвҖқ",
    '1:5': "ГўвҖҰвҖў",
    '2:5': "ГўвҖҰвҖ“",
    '3:5': "ГўвҖҰвҖ”",
    '4:5': "ГўвҖҰЛң",
    '1:6': "ГўвҖҰв„ў",
    '5:6': "ГўвҖҰЕЎ",
    '1:8': "ГўвҖҰвҖә",
    '3:8': "ГўвҖҰЕ“",
    '5:8': "ГўвҖҰВқ",
    '7:8': "ГўвҖҰЕҫ"
  };
  return map[frac.n + ":" + frac.d] || frac.toFraction(false);
}
console.log(toFraction(Fraction(0.25))); // ГӮВј
